-- W1.6 questions batch 6167/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cbdcc9ff-moex-00092', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '黑道小混混甲與乙在聊天過程中，得知乙昨晚行竊得手贓款1萬元現金。
甲心想：這 1 萬元是不義之財，若任乙花用不符「公平正義」，遂決定
「替天行道」。甲知道乙有嚴重毒癮，便向乙佯稱自己熟識一毒販，可以
極低之價格購得毒品。乙一聽之下，心中毒癮難耐，便拜託甲代其購買
毒品。甲故做扭捏，最後才佯裝極不甘願地收下乙的 1萬元幫忙買毒品。
甲拿到乙給的 1萬元之後，便將其花用一空，消聲匿跡。試問甲有何刑
責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "e3953f7a9f61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00093', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '偵查後，檢察官針對甲的竊盜案件提起公訴。法院在審查該起訴後，認
為檢察官所指出的證明方法顯不足認定被告有成立犯罪之可能，於是裁
定命檢察官補正。檢察官補正後，法院仍認，依起訴卷證不足以認定被
告有成立犯罪的可能，於是裁定駁回起訴。檢察官認法院駁回裁定違法。
請問，檢察官對於法院的裁定，得否聲明不服？請附詳細理由說明之。
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "e3953f7a9f61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00094', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '偵查後，檢察官以普通傷害罪起訴甲。在二審審判中，刑法修正，普通
傷害罪的法定刑由「三年以下有期徒刑、拘役或（銀元）一千元以下罰
金」，修正為「五年以下有期徒刑、拘役或（新臺幣）五十萬元以下罰金」。
法院在審理後，諭知有罪判決。甲不服，向最高法院提起上訴。請問，
此上訴是否合法？請附詳細理由說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "e3953f7a9f61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00095', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', 'A 縣農會受行政院農業委員會補助新臺幣（下同）500 萬元，A 縣政府
補助 450 萬元，辦理採購金額 1800 萬元之農產品加工廠改善工程。該
工程經公開招標後由 B營造有限公司（下稱 B公司）得標，A縣農會與
B 公司簽訂工程承攬契約書後，將 B 公司投標時繳納之押標金 90 萬元
全數轉作履約保證金；該工程經履約、驗收完畢後，A縣農會將履約保
證金發還 B 公司。嗣後 A 縣農會發現 B 公司有借用他人名義或證件投
標之事實，B公司所繳納之 90萬元押標金額應予沒收，而不應發還，乃
去函通知 B 公司於文到後 30 日內繳還該筆押標金。假設 B 公司置之不
理，A縣農會應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "6dcfb8d68ae0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00096', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '何謂「採購契約要項」與「採購契約範本」？假設 A機關與 B廠商簽訂
工程採購契約，卻未將採購契約要項及工程採購契約範本中關於逾期違
約金以契約價金總額 20%為上限之內容納入契約，B廠商得否逕依此主
張契約違約金超過 20%部分無效？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "6dcfb8d68ae0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00097', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', 'A鄉公所辦理「產業觀光主題園區建置工程」，進行公開招標，經評選後
由 B公司得標。工程完工驗收合格後，依契約約定，設施及設備之保固
期間為 3 年，植栽養護期間為 2 年。園區開放使用 6 個月後，園區內休
憩步道及多項設施均損壞不堪使用，喬、灌木與草皮均枯萎，幾無存活。
A鄉公所乃依合約中關於保固之規定，通知B公司改善。B公司主張設施
與植栽損害為入園民眾之人為破壞，非屬保固責任範圍，A鄉公所遂通知
B公司沒收新臺幣60萬元之保固保證金。此外，並依政府採購法第101條
第1項第9款之規定，將事實及理由通知B公司，表示將刊登政府採購公
報列為不良廠商。B公司對於此二通知均不服，應如何救濟？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "6dcfb8d68ae0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00098', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-110-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', 'A縣政府環保局（下稱 A環保局）辦理「A縣環境綠化及生態保育推廣
計畫」技術服務契約採購，由 B公司得標。A環保局與 B公司簽約後，
B公司之負責人甲乃交付A環保局辦理採購人員乙先前應允之後謝金新
臺幣 70萬元。甲與乙之刑事責任部分暫時不論，政府採購法對廠商此等
行為有何相關規範？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "6dcfb8d68ae0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00001', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何項原則不屬於罪刑法定原則之內涵？', '["禁止類推適用原則", "罪刑明確性原則", "不利益變更禁止原則", "禁止溯及既往原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00002', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關法律變更的敘述，下列何者正確？', '["依刑法第2條第1項本文之規定，行為後法律有變更時，原則上適用裁判時之法律", "刑法第2條第1項所稱之法律，僅限於涉及犯罪成立之要件，而不含刑罰效果", "依刑法第2條第2項之規定，沒收與所有的保安處分均適用裁判時之法律", "刑罰之內容於行為後有變更者，結論上應適用最有利於行為人之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00003', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '依刑法規定、實務及通說見解，下列何者之情形不該當刑法上之重傷概念？', '["甲將乙右手大拇指、食指及中指砍斷，僅留無名指與小指", "甲用球棒毆打乙，使乙之膝關節無法伸直", "甲用球棒毆打乙，使乙昏迷成為植物人", "甲用球棒毆打乙，使乙腳骨折經一年復健始能正常行走"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
